package com.panini.back.entity;
import jakarta.persistence.*;
@Entity @Table(name="collection_items", uniqueConstraints=@UniqueConstraint(columnNames={"user_id","sticker_code"})) public class CollectionItem { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(optional=false) @JoinColumn(name="user_id") private User user; @ManyToOne(optional=false) @JoinColumn(name="sticker_code", referencedColumnName="code") private Sticker sticker; @Column(nullable=false) private Integer quantityOwned=0; @Column(nullable=false) private Boolean favorite=false; public Long getId(){return id;} public void setId(Long id){this.id=id;} public User getUser(){return user;} public void setUser(User user){this.user=user;} public Sticker getSticker(){return sticker;} public void setSticker(Sticker sticker){this.sticker=sticker;} public Integer getQuantityOwned(){return quantityOwned;} public void setQuantityOwned(Integer quantityOwned){this.quantityOwned=quantityOwned;} public Boolean getFavorite(){return favorite;} public void setFavorite(Boolean favorite){this.favorite=favorite;} }
